@Test public void supplementaryPlaneCharacter() {
    String text = "&#128512;";
    assertEquals("\uD83D\uDE00", Entities.unescape(text));
}

@Test public void invalidHighCharacterValue() {
    String text = "&#1114112;";
    String result = Entities.unescape(text);
    assertEquals("&#1114112;", result);
}

@Test public void boundaryCharacterValue() {
    String text = "&#65535;";
    assertEquals("\uFFFF", Entities.unescape(text));
}

@Test public void charValueJustOverBoundary() {
    String text = "&#65536;";
    String result = Entities.unescape(text);
    assertEquals("&#65536;", result);
}
